import{_ as e,H as l,f as o,i as a}from"./chunks/framework.DqVL7uya.js";const p=JSON.parse('{"title":"Build ISO","description":"","frontmatter":{},"headers":[],"relativePath":"iso.md","filePath":"iso.md"}'),t={name:"iso.md"};function s(r,i,d,n,c,u){return l(),o("div",null,[...i[0]||(i[0]=[a('<h1 id="build-iso" tabindex="-1">Build ISO <a class="header-anchor" href="#build-iso" aria-label="Permalink to &quot;Build ISO&quot;">​</a></h1><p>This repository does not ship an <code>archiso</code> profile. Build your ISO with your own profile and include the package lists from:</p><ul><li><code>install/omarchy-base.packages</code></li><li><code>install/omarchy-other.packages</code></li></ul><p>Then run the installer on first boot.</p><h2 id="linux-native-build" tabindex="-1">Linux (native build) <a class="header-anchor" href="#linux-native-build" aria-label="Permalink to &quot;Linux (native build)&quot;">​</a></h2><p>Prerequisites:</p><ul><li>Arch or Arch-based host</li><li><code>archiso</code> installed</li><li>10-20 GB of free disk space</li><li><code>git</code> and <code>sudo</code></li></ul><p>Steps:</p><ol><li>Install archiso: <ul><li><code>sudo pacman -S --needed archiso</code></li></ul></li><li>Copy an official profile as a base: <ul><li><code>cp -r /usr/share/archiso/configs/releng ./arcalos-iso</code></li></ul></li><li>Add packages to <code>./arcalos-iso/packages.x86_64</code>: <ul><li>Append the contents of <code>install/omarchy-base.packages</code></li><li>Append the contents of <code>install/omarchy-other.packages</code></li></ul></li><li>Build the ISO: <ul><li><code>mkarchiso -v -w work -o out ./arcalos-iso</code></li></ul></li><li>Boot the ISO and run the online installer from the live system.</li></ol><h2 id="macos-build-in-a-linux-vm" tabindex="-1">macOS (build in a Linux VM) <a class="header-anchor" href="#macos-build-in-a-linux-vm" aria-label="Permalink to &quot;macOS (build in a Linux VM)&quot;">​</a></h2><p>Prerequisites:</p><ul><li>A Linux VM (UTM, VirtualBox, VMware, etc.)</li><li>20+ GB of free disk space for the VM</li><li>A shared folder to copy the ISO out</li></ul><p>Steps:</p><ol><li>Create an Arch or Arch-based Linux VM.</li><li>Install <code>archiso</code> inside the VM.</li><li>Follow the Linux steps above to build the ISO.</li><li>Copy the ISO to the host using the shared folder.</li></ol><h2 id="windows-build-in-a-linux-vm" tabindex="-1">Windows (build in a Linux VM) <a class="header-anchor" href="#windows-build-in-a-linux-vm" aria-label="Permalink to &quot;Windows (build in a Linux VM)&quot;">​</a></h2><p>Prerequisites:</p><ul><li>A Linux VM (Hyper-V, VirtualBox, VMware, etc.)</li><li>20+ GB of free disk space for the VM</li><li>A shared folder to copy the ISO out</li></ul><p>Notes:</p><ul><li><code>archiso</code> requires Linux with loop devices and elevated privileges.</li><li>WSL2 is not a reliable environment for building <code>archiso</code> images.</li></ul><p>Steps:</p><ol><li>Create an Arch or Arch-based Linux VM.</li><li>Install <code>archiso</code> inside the VM.</li><li>Follow the Linux steps above to build the ISO.</li><li>Copy the ISO to the host using the shared folder.</li></ol>',21)])])}const f=e(t,[["render",s]]);export{p as __pageData,f as default};
